import{_ as n,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const a="/images/uebung033.jpg",m=JSON.parse('{"title":"Übung Lektion 21","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung21.md","filePath":"lektionen/uebung21.md"}'),s={name:"lektionen/uebung21.md"};function o(p,e,d,u,l,g){return t(),r("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-21" tabindex="-1">Übung Lektion 21 <a class="header-anchor" href="#ubung-lektion-21" aria-label="Permalink to &quot;Übung Lektion 21&quot;">​</a></h1><p>A) Lösen Sie folgende Komposita in Sanskrit auf und übersetzen Sie sie:</p><p>१. अनादिकालिकसंसरः । der Lauf durch die Wiedergeburten ohne Anfang und feste Zeitdauer</p><p>२. अनादिमध्यान्तः । ohne Anfang, Mitte und Ende</p><p>३. महामैत्रीकरुणाचित्तः । mit einem Herz voll großen Wohlwollens und Mitgefühls</p><p>४. सर्वहतान्धकारः । der überall die Finsternis zerstört hat</p><p>B) Übersetzen Sie:</p><p>मृतं दहन्नग्निः सतीमपि दहति ॥१॥ Das Feuer, das den Toten verbrennt, verbrennt auch die treue Gattin (सती).</p><p>सद्गुरुर्महाकविस्तोत्रैर्महादेवं स्तौति ॥२॥ Der gute Meister preist den großen Gott mit Lobliedern der großen Dichters.</p><p>महान्ति फलान्यदन्तो बाला जलमापि पिबन्ति ॥३॥ Die Knaben, die große Früchte essen, trinken auch Wasser.</p><p>पुजां कुर्वञ्जनो यजते च स्तौति च देवताम् ॥४॥ Während der Verehrung opfert und preist der Mann die Gottheit.</p><p>गुरूपनीतनरो द्विजः ॥५॥ Ein Zweimalgeborener ist ein Mann, der vom Meister in den Veda initiiert wurde.</p><p>जितक्रोधो घ्नन्तमप्यरिं न द्वेष्टि । क्रोधजितस्तु द्वेष्टि ॥६॥ Wer den Zorn besiegt hat, der hasst einen Feind nicht, auch wenn dieser ihn tötet. Wer aber vom Zorn besiegt ist, hasst.</p><p><img src="'+a+'" alt=""><br> Abb.: हतान्धकारा दीपाः<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/3099964027/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/3099964027/</a>. -- Zugriff am 2008-12-23. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p>',15)])])}const h=n(s,[["render",o]]);export{m as __pageData,h as default};
